```class Solution {
public:
    int minSteps(string s, string t) {
        vector<int> cnts(26, 0), cntt(26, 0);
        for (char c : s) cnts[c - 'a']++;
        for (char c : t) cntt[c - 'a']++;
        int res = 0;
        for (int i = 0; i < 26; i++) res += abs(cnts[i] - cntt[i]);
        return res / 2;
    }
};
